import{_ as i,o as a,c as t,ag as o}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"Scope Management","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/scope-management.md","filePath":"admin-ui/scope-management.md"}'),n={name:"admin-ui/scope-management.md"};function s(r,e,l,c,d,g){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="scope-management" tabindex="-1">Scope Management <a class="header-anchor" href="#scope-management" aria-label="Permalink to &quot;Scope Management&quot;">​</a></h1><p>The Scope Management section provides comprehensive tools for configuring FHIR resource permissions, creating role-based access templates, and managing granular data access control within the SMART on FHIR platform.</p><h2 id="🎯-scope-overview" tabindex="-1">🎯 Scope Overview <a class="header-anchor" href="#🎯-scope-overview" aria-label="Permalink to &quot;🎯 Scope Overview&quot;">​</a></h2><h3 id="understanding-smart-scopes" tabindex="-1">Understanding SMART Scopes <a class="header-anchor" href="#understanding-smart-scopes" aria-label="Permalink to &quot;Understanding SMART Scopes&quot;">​</a></h3><p>SMART scopes define what data an application can access and what operations it can perform. Scopes follow the pattern: <code>{context}/{resource}.{operations}</code></p><h4 id="context-prefixes" tabindex="-1">Context Prefixes <a class="header-anchor" href="#context-prefixes" aria-label="Permalink to &quot;Context Prefixes&quot;">​</a></h4><ul><li><strong>patient/</strong>: Access to resources where patient is the subject</li><li><strong>user/</strong>: Access to resources accessible by authenticated user</li><li><strong>system/</strong>: Backend system access without user context</li><li><strong>agent/</strong>: Autonomous agent access for AI/ML systems</li></ul><h4 id="resource-types" tabindex="-1">Resource Types <a class="header-anchor" href="#resource-types" aria-label="Permalink to &quot;Resource Types&quot;">​</a></h4><p>Common FHIR resources with scope support:</p><ul><li><strong>Patient</strong>: Demographics and patient information</li><li><strong>Observation</strong>: Clinical observations and measurements</li><li><strong>MedicationRequest</strong>: Medication orders and prescriptions</li><li><strong>DiagnosticReport</strong>: Lab results and imaging reports</li><li><strong>Condition</strong>: Diagnoses and health conditions</li><li><strong>Procedure</strong>: Medical procedures and interventions</li><li><strong>Encounter</strong>: Healthcare encounters and visits</li><li><strong>Practitioner</strong>: Healthcare provider information</li></ul><h4 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h4><ul><li><strong>read</strong>: Read access to specific resources</li><li><strong>write</strong>: Create and update resource capabilities</li><li><strong>cruds</strong>: Full Create, Read, Update, Delete, Search operations</li><li><strong>search</strong>: Search and query capabilities</li></ul><h2 id="📋-scope-templates" tabindex="-1">📋 Scope Templates <a class="header-anchor" href="#📋-scope-templates" aria-label="Permalink to &quot;📋 Scope Templates&quot;">​</a></h2><h3 id="pre-built-role-templates" tabindex="-1">Pre-built Role Templates <a class="header-anchor" href="#pre-built-role-templates" aria-label="Permalink to &quot;Pre-built Role Templates&quot;">​</a></h3><h4 id="clinical-roles" tabindex="-1">Clinical Roles <a class="header-anchor" href="#clinical-roles" aria-label="Permalink to &quot;Clinical Roles&quot;">​</a></h4><ul><li><p><strong>👨‍⚕️ Primary Care Provider</strong></p><ul><li><code>user/Patient.read</code> - Patient demographics</li><li><code>user/Observation.read</code> - Vital signs and lab results</li><li><code>user/MedicationRequest.cruds</code> - Medication management</li><li><code>user/Condition.cruds</code> - Diagnosis management</li><li><code>user/DiagnosticReport.read</code> - Lab and imaging results</li></ul></li><li><p><strong>👩‍⚕️ Specialist Physician</strong></p><ul><li><code>user/Patient.read</code> - Patient information</li><li><code>user/Observation.read</code> - Clinical observations</li><li><code>user/Procedure.cruds</code> - Procedure documentation</li><li><code>user/DiagnosticReport.read</code> - Diagnostic results</li><li><code>user/CarePlan.cruds</code> - Treatment planning</li></ul></li><li><p><strong>👩‍⚕️ Registered Nurse</strong></p><ul><li><code>user/Patient.read</code> - Patient demographics</li><li><code>user/Observation.cruds</code> - Vital signs and assessments</li><li><code>user/MedicationAdministration.cruds</code> - Medication administration</li><li><code>user/CarePlan.read</code> - Care plan review</li><li><code>user/Task.cruds</code> - Nursing tasks and assignments</li></ul></li></ul><h4 id="administrative-roles" tabindex="-1">Administrative Roles <a class="header-anchor" href="#administrative-roles" aria-label="Permalink to &quot;Administrative Roles&quot;">​</a></h4><ul><li><p><strong>👨‍💼 Health Information Manager</strong></p><ul><li><code>user/Patient.read</code> - Patient directory access</li><li><code>user/*.read</code> - Read access to all clinical data</li><li><code>user/AuditEvent.read</code> - Access audit trails</li><li><code>user/Organization.read</code> - Organizational information</li></ul></li><li><p><strong>📊 Clinical Researcher</strong></p><ul><li><code>user/Patient.read</code> - De-identified patient data</li><li><code>user/Observation.read</code> - Research data access</li><li><code>user/Condition.read</code> - Diagnosis information</li><li><code>user/Procedure.read</code> - Procedure data</li><li><code>user/MedicationRequest.read</code> - Medication data</li></ul></li></ul><h3 id="custom-template-creation" tabindex="-1">Custom Template Creation <a class="header-anchor" href="#custom-template-creation" aria-label="Permalink to &quot;Custom Template Creation&quot;">​</a></h3><h4 id="template-builder-interface" tabindex="-1">Template Builder Interface <a class="header-anchor" href="#template-builder-interface" aria-label="Permalink to &quot;Template Builder Interface&quot;">​</a></h4><ul><li><strong>📛 Template Name</strong>: Descriptive template identifier</li><li><strong>📋 Description</strong>: Template purpose and usage</li><li><strong>🎯 Target Role</strong>: Intended user role or job function</li><li><strong>🏢 Organization</strong>: Organizational scope and applicability</li></ul><h4 id="scope-selection" tabindex="-1">Scope Selection <a class="header-anchor" href="#scope-selection" aria-label="Permalink to &quot;Scope Selection&quot;">​</a></h4><ul><li><strong>🔍 Resource Browser</strong>: Visual FHIR resource selection</li><li><strong>⚙️ Operation Matrix</strong>: Granular operation permissions</li><li><strong>🎯 Context Assignment</strong>: Context prefix configuration</li><li><strong>✅ Validation</strong>: Scope combination validation</li></ul><h4 id="template-testing" tabindex="-1">Template Testing <a class="header-anchor" href="#template-testing" aria-label="Permalink to &quot;Template Testing&quot;">​</a></h4><ul><li><strong>🧪 Dry Run</strong>: Test scope combinations</li><li><strong>📊 Access Simulation</strong>: Simulate user access patterns</li><li><strong>🔍 Permission Audit</strong>: Review effective permissions</li><li><strong>📋 Compliance Check</strong>: Regulatory compliance validation</li></ul><h2 id="🔐-granular-permissions" tabindex="-1">🔐 Granular Permissions <a class="header-anchor" href="#🔐-granular-permissions" aria-label="Permalink to &quot;🔐 Granular Permissions&quot;">​</a></h2><h3 id="resource-level-permissions" tabindex="-1">Resource-Level Permissions <a class="header-anchor" href="#resource-level-permissions" aria-label="Permalink to &quot;Resource-Level Permissions&quot;">​</a></h3><h4 id="patient-data-access" tabindex="-1">Patient Data Access <a class="header-anchor" href="#patient-data-access" aria-label="Permalink to &quot;Patient Data Access&quot;">​</a></h4><ul><li><strong>patient/Patient.read</strong>: Patient&#39;s own demographic data</li><li><strong>patient/Observation.read</strong>: Patient&#39;s clinical observations</li><li><strong>patient/MedicationRequest.read</strong>: Patient&#39;s medication orders</li><li><strong>patient/AllergyIntolerance.read</strong>: Patient&#39;s allergy information</li><li><strong>patient/Immunization.read</strong>: Patient&#39;s immunization records</li></ul><h4 id="provider-workflow-permissions" tabindex="-1">Provider Workflow Permissions <a class="header-anchor" href="#provider-workflow-permissions" aria-label="Permalink to &quot;Provider Workflow Permissions&quot;">​</a></h4><ul><li><strong>user/Patient.search</strong>: Search patient directory</li><li><strong>user/Encounter.read</strong>: Access patient encounters</li><li><strong>user/CareTeam.read</strong>: View care team assignments</li><li><strong>user/Schedule.read</strong>: Access scheduling information</li><li><strong>user/Appointment.cruds</strong>: Manage appointments</li></ul><h4 id="system-integration-permissions" tabindex="-1">System Integration Permissions <a class="header-anchor" href="#system-integration-permissions" aria-label="Permalink to &quot;System Integration Permissions&quot;">​</a></h4><ul><li><strong>system/Patient.read</strong>: System-wide patient access</li><li><strong>system/Bundle.read</strong>: FHIR bundle operations</li><li><strong>system/OperationOutcome.read</strong>: Operation result access</li><li><strong>system/AuditEvent.cruds</strong>: Audit event management</li></ul><h3 id="operation-specific-controls" tabindex="-1">Operation-Specific Controls <a class="header-anchor" href="#operation-specific-controls" aria-label="Permalink to &quot;Operation-Specific Controls&quot;">​</a></h3><h4 id="read-operations" tabindex="-1">Read Operations <a class="header-anchor" href="#read-operations" aria-label="Permalink to &quot;Read Operations&quot;">​</a></h4><ul><li><strong>Basic Read</strong>: Single resource retrieval by ID</li><li><strong>Search</strong>: Resource search with query parameters</li><li><strong>History</strong>: Resource version history access</li><li><strong>Include</strong>: Related resource inclusion in queries</li></ul><h4 id="write-operations" tabindex="-1">Write Operations <a class="header-anchor" href="#write-operations" aria-label="Permalink to &quot;Write Operations&quot;">​</a></h4><ul><li><strong>Create</strong>: New resource creation</li><li><strong>Update</strong>: Existing resource modification</li><li><strong>Patch</strong>: Partial resource updates</li><li><strong>Delete</strong>: Resource deletion (soft or hard delete)</li></ul><h4 id="advanced-operations" tabindex="-1">Advanced Operations <a class="header-anchor" href="#advanced-operations" aria-label="Permalink to &quot;Advanced Operations&quot;">​</a></h4><ul><li><strong>Validate</strong>: Resource validation operations</li><li><strong>Transform</strong>: Data transformation operations</li><li><strong>Export</strong>: Bulk data export capabilities</li><li><strong>Import</strong>: Bulk data import operations</li></ul><h2 id="🏢-organizational-scope-management" tabindex="-1">🏢 Organizational Scope Management <a class="header-anchor" href="#🏢-organizational-scope-management" aria-label="Permalink to &quot;🏢 Organizational Scope Management&quot;">​</a></h2><h3 id="multi-tenant-support" tabindex="-1">Multi-Tenant Support <a class="header-anchor" href="#multi-tenant-support" aria-label="Permalink to &quot;Multi-Tenant Support&quot;">​</a></h3><h4 id="organization-hierarchies" tabindex="-1">Organization Hierarchies <a class="header-anchor" href="#organization-hierarchies" aria-label="Permalink to &quot;Organization Hierarchies&quot;">​</a></h4><ul><li><strong>🏥 Health System</strong>: Top-level health system permissions</li><li><strong>🏢 Hospital</strong>: Hospital-specific data access</li><li><strong>🏪 Clinic</strong>: Clinic or department-level permissions</li><li><strong>👥 Unit</strong>: Specific unit or team permissions</li></ul><h4 id="inheritance-models" tabindex="-1">Inheritance Models <a class="header-anchor" href="#inheritance-models" aria-label="Permalink to &quot;Inheritance Models&quot;">​</a></h4><ul><li><strong>⬇️ Cascading</strong>: Permissions cascade down hierarchy</li><li><strong>🔒 Isolated</strong>: Each level maintains separate permissions</li><li><strong>🔄 Hybrid</strong>: Mixed inheritance and isolation models</li><li><strong>🎯 Custom</strong>: Organization-defined inheritance rules</li></ul><h3 id="geographic-and-legal-boundaries" tabindex="-1">Geographic and Legal Boundaries <a class="header-anchor" href="#geographic-and-legal-boundaries" aria-label="Permalink to &quot;Geographic and Legal Boundaries&quot;">​</a></h3><h4 id="regional-compliance" tabindex="-1">Regional Compliance <a class="header-anchor" href="#regional-compliance" aria-label="Permalink to &quot;Regional Compliance&quot;">​</a></h4><ul><li><strong>🌍 GDPR</strong>: European data protection compliance</li><li><strong>🇺🇸 HIPAA</strong>: US healthcare privacy requirements</li><li><strong>🇨🇦 PIPEDA</strong>: Canadian privacy legislation</li><li><strong>🌏 Local Laws</strong>: Country-specific requirements</li></ul><h4 id="cross-border-data-access" tabindex="-1">Cross-Border Data Access <a class="header-anchor" href="#cross-border-data-access" aria-label="Permalink to &quot;Cross-Border Data Access&quot;">​</a></h4><ul><li><strong>🌐 Data Residency</strong>: Geographic data storage requirements</li><li><strong>🔒 Encryption</strong>: Cross-border data encryption</li><li><strong>📋 Consent</strong>: Patient consent for data sharing</li><li><strong>🛡️ Security</strong>: Additional security measures</li></ul><h2 id="📊-scope-analytics-and-monitoring" tabindex="-1">📊 Scope Analytics and Monitoring <a class="header-anchor" href="#📊-scope-analytics-and-monitoring" aria-label="Permalink to &quot;📊 Scope Analytics and Monitoring&quot;">​</a></h2><h3 id="usage-analytics" tabindex="-1">Usage Analytics <a class="header-anchor" href="#usage-analytics" aria-label="Permalink to &quot;Usage Analytics&quot;">​</a></h3><h4 id="permission-utilization" tabindex="-1">Permission Utilization <a class="header-anchor" href="#permission-utilization" aria-label="Permalink to &quot;Permission Utilization&quot;">​</a></h4><ul><li><strong>📊 Access Patterns</strong>: Most/least used permissions</li><li><strong>👥 User Activity</strong>: Per-user permission usage</li><li><strong>📱 Application Usage</strong>: App-specific scope utilization</li><li><strong>⏰ Temporal Patterns</strong>: Time-based access patterns</li></ul><h4 id="security-monitoring" tabindex="-1">Security Monitoring <a class="header-anchor" href="#security-monitoring" aria-label="Permalink to &quot;Security Monitoring&quot;">​</a></h4><ul><li><strong>🚨 Violations</strong>: Scope violation attempts</li><li><strong>❌ Denied Access</strong>: Permission denial tracking</li><li><strong>🔍 Anomalies</strong>: Unusual access pattern detection</li><li><strong>📋 Audit Trails</strong>: Comprehensive access logging</li></ul><h3 id="compliance-reporting" tabindex="-1">Compliance Reporting <a class="header-anchor" href="#compliance-reporting" aria-label="Permalink to &quot;Compliance Reporting&quot;">​</a></h3><h4 id="access-reviews" tabindex="-1">Access Reviews <a class="header-anchor" href="#access-reviews" aria-label="Permalink to &quot;Access Reviews&quot;">​</a></h4><ul><li><strong>📅 Periodic Reviews</strong>: Regular permission reviews</li><li><strong>👥 User Certification</strong>: User access certification</li><li><strong>📊 Compliance Reports</strong>: Regulatory compliance reporting</li><li><strong>🔍 Risk Assessment</strong>: Permission-based risk analysis</li></ul><h4 id="change-management" tabindex="-1">Change Management <a class="header-anchor" href="#change-management" aria-label="Permalink to &quot;Change Management&quot;">​</a></h4><ul><li><strong>📋 Change Logs</strong>: Permission modification history</li><li><strong>✅ Approval Workflows</strong>: Change approval processes</li><li><strong>🧪 Testing</strong>: Permission change testing</li><li><strong>📊 Impact Analysis</strong>: Change impact assessment</li></ul><h2 id="🛠️-scope-administration" tabindex="-1">🛠️ Scope Administration <a class="header-anchor" href="#🛠️-scope-administration" aria-label="Permalink to &quot;🛠️ Scope Administration&quot;">​</a></h2><h3 id="template-management" tabindex="-1">Template Management <a class="header-anchor" href="#template-management" aria-label="Permalink to &quot;Template Management&quot;">​</a></h3><h4 id="template-lifecycle" tabindex="-1">Template Lifecycle <a class="header-anchor" href="#template-lifecycle" aria-label="Permalink to &quot;Template Lifecycle&quot;">​</a></h4><ul><li><strong>➕ Creation</strong>: New template development</li><li><strong>🧪 Testing</strong>: Template validation and testing</li><li><strong>🚀 Deployment</strong>: Template activation and assignment</li><li><strong>🔄 Updates</strong>: Template modification and versioning</li><li><strong>🗄️ Archival</strong>: Template retirement and archival</li></ul><h4 id="version-control" tabindex="-1">Version Control <a class="header-anchor" href="#version-control" aria-label="Permalink to &quot;Version Control&quot;">​</a></h4><ul><li><strong>📊 Versioning</strong>: Template version management</li><li><strong>🔄 Migration</strong>: User migration to new versions</li><li><strong>📋 Rollback</strong>: Revert to previous template versions</li><li><strong>📊 Comparison</strong>: Template version comparison</li></ul><h3 id="user-assignment" tabindex="-1">User Assignment <a class="header-anchor" href="#user-assignment" aria-label="Permalink to &quot;User Assignment&quot;">​</a></h3><h4 id="assignment-methods" tabindex="-1">Assignment Methods <a class="header-anchor" href="#assignment-methods" aria-label="Permalink to &quot;Assignment Methods&quot;">​</a></h4><ul><li><strong>👤 Individual</strong>: Direct user assignment</li><li><strong>👥 Group</strong>: Group-based assignment</li><li><strong>🎯 Role</strong>: Role-based assignment</li><li><strong>🤖 Automatic</strong>: Rule-based automatic assignment</li></ul><h4 id="assignment-validation" tabindex="-1">Assignment Validation <a class="header-anchor" href="#assignment-validation" aria-label="Permalink to &quot;Assignment Validation&quot;">​</a></h4><ul><li><strong>✅ Compatibility</strong>: User role compatibility check</li><li><strong>🔍 Conflicts</strong>: Permission conflict detection</li><li><strong>📋 Requirements</strong>: Minimum permission validation</li><li><strong>🛡️ Security</strong>: Security policy compliance</li></ul><h2 id="🔍-troubleshooting" tabindex="-1">🔍 Troubleshooting <a class="header-anchor" href="#🔍-troubleshooting" aria-label="Permalink to &quot;🔍 Troubleshooting&quot;">​</a></h2><h3 id="common-scope-issues" tabindex="-1">Common Scope Issues <a class="header-anchor" href="#common-scope-issues" aria-label="Permalink to &quot;Common Scope Issues&quot;">​</a></h3><h4 id="permission-conflicts" tabindex="-1">Permission Conflicts <a class="header-anchor" href="#permission-conflicts" aria-label="Permalink to &quot;Permission Conflicts&quot;">​</a></h4><ul><li><strong>🚨 Overlapping Scopes</strong>: Conflicting permission combinations</li><li><strong>❌ Insufficient Access</strong>: Missing required permissions</li><li><strong>🔒 Over-Privileged</strong>: Excessive permission grants</li><li><strong>🎯 Misaligned Context</strong>: Incorrect context prefix usage</li></ul><h4 id="application-integration" tabindex="-1">Application Integration <a class="header-anchor" href="#application-integration" aria-label="Permalink to &quot;Application Integration&quot;">​</a></h4><ul><li><strong>📱 App Registration</strong>: Application scope configuration</li><li><strong>🔐 OAuth Flow</strong>: Authorization scope handling</li><li><strong>🎯 Launch Context</strong>: Context-scope alignment</li><li><strong>📊 Resource Access</strong>: FHIR resource accessibility</li></ul><h3 id="diagnostic-tools" tabindex="-1">Diagnostic Tools <a class="header-anchor" href="#diagnostic-tools" aria-label="Permalink to &quot;Diagnostic Tools&quot;">​</a></h3><h4 id="scope-validators" tabindex="-1">Scope Validators <a class="header-anchor" href="#scope-validators" aria-label="Permalink to &quot;Scope Validators&quot;">​</a></h4><ul><li><strong>✅ Syntax Check</strong>: Scope syntax validation</li><li><strong>🔍 Compatibility</strong>: FHIR version compatibility</li><li><strong>📋 Standards</strong>: SMART specification compliance</li><li><strong>🛡️ Security</strong>: Security best practice validation</li></ul><h4 id="access-simulators" tabindex="-1">Access Simulators <a class="header-anchor" href="#access-simulators" aria-label="Permalink to &quot;Access Simulators&quot;">​</a></h4><ul><li><strong>🧪 User Simulation</strong>: Simulate user access scenarios</li><li><strong>📱 App Testing</strong>: Test application access patterns</li><li><strong>🎯 Context Testing</strong>: Launch context simulation</li><li><strong>📊 Permission Testing</strong>: Effective permission verification</li></ul><h2 id="📈-best-practices" tabindex="-1">📈 Best Practices <a class="header-anchor" href="#📈-best-practices" aria-label="Permalink to &quot;📈 Best Practices&quot;">​</a></h2><h3 id="scope-design-principles" tabindex="-1">Scope Design Principles <a class="header-anchor" href="#scope-design-principles" aria-label="Permalink to &quot;Scope Design Principles&quot;">​</a></h3><ol><li><strong>🎯 Least Privilege</strong>: Grant minimum necessary permissions</li><li><strong>🔒 Defense in Depth</strong>: Multiple permission layers</li><li><strong>📋 Clear Documentation</strong>: Document scope purposes</li><li><strong>🧪 Regular Testing</strong>: Validate scope effectiveness</li></ol><h3 id="template-management-1" tabindex="-1">Template Management <a class="header-anchor" href="#template-management-1" aria-label="Permalink to &quot;Template Management&quot;">​</a></h3><ol><li><strong>🎯 Role Alignment</strong>: Align templates with job functions</li><li><strong>🔄 Regular Review</strong>: Periodic template review and updates</li><li><strong>📊 Usage Monitoring</strong>: Track template utilization</li><li><strong>🛡️ Security Focus</strong>: Prioritize security in template design</li></ol><h3 id="compliance-management" tabindex="-1">Compliance Management <a class="header-anchor" href="#compliance-management" aria-label="Permalink to &quot;Compliance Management&quot;">​</a></h3><ol><li><strong>📋 Documentation</strong>: Maintain comprehensive documentation</li><li><strong>🔍 Regular Audits</strong>: Conduct permission audits</li><li><strong>📊 Reporting</strong>: Generate compliance reports</li><li><strong>🔄 Continuous Improvement</strong>: Iteratively improve processes</li></ol><p>The Scope Management system provides the foundation for secure, compliant, and efficient data access control within the SMART on FHIR healthcare ecosystem.</p><h2 id="related-sub-tabs" tabindex="-1">Related Sub-Tabs <a class="header-anchor" href="#related-sub-tabs" aria-label="Permalink to &quot;Related Sub-Tabs&quot;">​</a></h2><p>The <strong>SMART Config</strong> page in the admin UI contains three sub-tabs:</p><ul><li><strong>Scopes</strong> — Scope configuration (documented above)</li><li><strong>Launch Context</strong> — Per-user SMART launch context management. See the dedicated <a href="./launch-context">Launch Context</a> page.</li><li><strong>Protocol Mappers</strong> — Diagnostic view and repair tool for SMART scope protocol mappers in Keycloak. Lists all configured mappers, detects issues, and provides a one-click fix action via <code>POST /admin/scope-mappers/fix</code>.</li></ul>',95)])])}const m=i(n,[["render",s]]);export{p as __pageData,m as default};
